    AnalysisArtifact, LockClassKey, LockInfoArtifact, LockUsageBitsArtifact,
    LockUsageSiteArtifact, LockUsageStateArtifact, SourceLocation,
};
use clap::Parser;

#[derive(Debug, Parser)]
#[command(
    author,
    version,
    about = "Asterinas static lock dependency analysis driver"
)]
struct Cli {
    #[arg(long, default_value = "Cargo.toml")]
    manifest_path: PathBuf,
