impl UnixSocketAddr {
    pub(super) fn bind(self) -> Result<UnixSocketAddrBound> {
        let bound = match self {
            Self::Unnamed => UnixSocketAddrBound::Abstract(ns::alloc_ephemeral_abstract_name()?),
            Self::Path(path_name) => {
